scwin.gridForceYnDisplayFormatter = function (value) {
  switch (value) {
    case "1":
      return "Y";
    case "2":
      return "J";
    default:
      return "N";
  }
};

//-------------------------------------------------------------------------
// 작업장 onchange
//-------------------------------------------------------------------------
scwin.lc_wrkPlCd_onchange = function (info) {
  if (info.newValue == "5C08") {
    gr_result.setColumnOrder(["wrkPlCd", "crryinoutIntendNo", "crryinoutIntendHh", "impExpClsCd", "arrvlportDtm", "crryinoutClsCd", "cntrNo", "cntrSizCd", "cntrTypCd", "fullEmptyClsCd", "sealNo", "lineCd", "blckCd", "wrkMemo", "wt", "selfClsCd", "vehclNo", "vehclIdCardNo", "odrNo", "cntrSeq", "wrkPathSeq", "wrkStpSeq", "crryinoutIntendDt", "selfTransCoClntNo", "blNo", "bookingNo", "cnclDtm", "cnclPicId", "forceYn", "onoffNo", "wrkStsCd"]);
  } else {
    gr_result.setColumnOrder(["wrkPlCd", "crryinoutIntendNo", "crryinoutIntendHh", "impExpClsCd", "arrvlportDtm", "crryinoutClsCd", "cntrNo", "cntrSizCd", "cntrTypCd", "fullEmptyClsCd", "sealNo", "wt", "selfClsCd", "vehclNo", "vehclIdCardNo", "odrNo", "cntrSeq", "wrkPathSeq", "wrkStpSeq", "crryinoutIntendDt", "selfTransCoClntNo", "blNo", "bookingNo", "lineCd", "blckCd", "cnclDtm", "cnclPicId", "wrkMemo", "forceYn", "onoffNo", "wrkStsCd"]);
  }
};

//-------------------------------------------------------------------------
// 그리드 onafteredit
//-------------------------------------------------------------------------
scwin.gr_result_onafteredit = function (rowIndex, columnIndex, value) {
  let colId = ds_result.getColumnID(columnIndex);
  switch (colId) {
    case "vehclNo":
      // 광주CY인 경우만 이벤트 발생. seal, full/empty 구분값만  넣고 저장하는경우
      // 라인코드 이벤트가 안먹기 때문에 차량번호에 이벤트 발생하도록 변경.
      // 2015.09.11 hurrah
      if (lc_wrkPlCd.getValue() == "5C08") {
        let v_line = ds_result.getCellData(rowIndex, "lineCd");
        let v_siz = ds_result.getCellData(rowIndex, "cntrSizCd");
        let v_typ = ds_result.getCellData(rowIndex, "cntrTypCd");
        let v_clsCd = ds_result.getCellData(rowIndex, "crryinoutClsCd");
        scwin.f_retrieveBlockInfo(v_line, v_siz, v_typ, rowIndex, v_clsCd);
      }
      break;
    case "lineCd":
      if (ds_result.getCellData(rowIndex, "lineCd") != "" && ds_result.getCellData(rowIndex, "fullEmptyClsCd") == "E") {
        let v_siz = ds_result.getCellData(rowIndex, "cntrSizCd");
        let v_typ = ds_result.getCellData(rowIndex, "cntrTypCd");
        let v_clsCd = ds_result.getCellData(rowIndex, "crryinoutClsCd");
        scwin.f_retrieveBlockInfo(ds_result.getCellData(rowIndex, "lineCd"), v_siz, v_typ, rowIndex, v_clsCd);
      } else if (ds_result.getCellData(rowIndex, "wrkPlCd") == "5C08") {
        let v_siz = ds_result.getCellData(rowIndex, "cntrSizCd");
        let v_typ = ds_result.getCellData(rowIndex, "cntrTypCd");
        let v_clsCd = ds_result.getCellData(rowIndex, "crryinoutClsCd");
        scwin.f_retrieveBlockInfo(ds_result.getCellData(rowIndex, "lineCd"), v_siz, v_typ, rowIndex, v_clsCd);
      }
      break;
  }
};

